-- Kushwaha Store starter catalog import
-- DMart-style common supermarket/kirana assortment.
-- Prices/MRPs are estimated starter values; owner should verify from the admin panel before final selling.

on conflict (id) do update set
  name = excluded.name,
  sort_order = excluded.sort_order;

on conflict (id) do update set
  name = excluded.name,
  category_id = excluded.category_id,
  unit = excluded.unit,
  price = excluded.price,
  mrp = excluded.mrp,
  stock = excluded.stock,
  low_stock_at = excluded.low_stock_at,
  mark = excluded.mark,
  loose = excluded.loose,
  image_url = excluded.image_url,
  source_note = excluded.source_note,
  updated_at = now();
